async (page) => {
  // Continuous rat killing loop - 3 more rats
  for (let i = 0; i < 4; i++) {
    await page.waitForTimeout(7000);
    const state = await page.evaluate(() => {
      const s = window.__latestGameState;
      const m = window.__latestAsciiMap;
      const target = s.current_target;
      if (!target) {
        // No target - find and attack next rat
        if (m) {
          const lines = m.legendText.split('\n');
          for (const line of lines) {
            const match = line.match(/(E\d+) \[R\] Rat/);
            if (match) { window.__clickEntity(match[1]); break; }
          }
        }
      }
      return { pos: s.player_position, hp: s.player_stats.hp, level: s.player_stats.level,
        target: target ? {name: target.name, hp: target.hp} : null };
    });
    if (state.hp < 40) break; // safety: stop if HP too low
  }
  const final = await page.evaluate(() => {
    const s = window.__latestGameState;
    const m = window.__latestAsciiMap;
    return { pos: s.player_position, hp: s.player_stats.hp, level: s.player_stats.level,
      target: s.current_target ? {name: s.current_target.name, hp: s.current_target.hp} : null,
      legend: m ? m.legendText.split('\n').slice(0,10).join('\n') : '' };
  });
  return JSON.stringify(final);
}

