async (page) => {
  // Walk to Bubba
  const clickResult = await page.evaluate(() => {
    const s = window.__latestGameState;
    const bubba = s.nearby_entities.find(e => e.name === 'Bubba');
    if (bubba && bubba.on_screen) {
