  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    // Look for ALL entity types including any type 2, 5, 6, 7, etc.
    const byType = {};
    s.nearby_entities.forEach(e => {
      const key = `${e.type}:${e.name}`;
      if (!byType[key]) byType[key] = {count: 0, closest: 999};
      byType[key].count++;
      byType[key].closest = Math.min(byType[key].closest, e.distance);
    });

    const closeEntities = s.nearby_entities
      .filter(e => e.distance < 15)
      .map(e => `${e.name}(t=${e.type})[${e.distance.toFixed(1)}] at(${e.x},${e.y})`);

    return JSON.stringify({pos: s.player_position, close: closeEntities, types: Object.keys(byType)});
  });
  return state;
}

