async (page) => {
  const result = await page.evaluate(() => {
    const map = window.game?.map;
    if (!map) return 'no map';

    // Search entire map data for the object tile IDs
    const targetTileIds = [1027907, 996850, 144112, 161403, 233977, 259307, 144285];
    const foundAt = [];

    // Search in data/high layers
    for (let y = 0; y < 400; y++) {
      if (!map.data[y]) continue;
      for (let x = 0; x < 400; x++) {
        const t = map.data[y][x];
        if (t && targetTileIds.includes(t)) {
          foundAt.push({layer: 'data', x, y, tileId: t});
        }
      }
    }

    // Also check high layer
    if (map.high) {
      for (let y = 0; y < 400; y++) {
        if (!map.high[y]) continue;
        for (let x = 0; x < 400; x++) {
          const t = map.high[y][x];
          if (t && targetTileIds.includes(t)) {
            foundAt.push({layer: 'high', x, y, tileId: t});
          }
        }
      }
    }

    return JSON.stringify({foundAt: foundAt.slice(0,20), total: foundAt.length});
  });
  return result;
}

