        const s = window.__latestGameState;
        return s && s.inventory ? s.inventory.find(i => i.edible) : null;
      });
      if (food) {
        await page.evaluate((slot) => window.game.menu.getInventory().selectEdible(slot), food.slot);
        await page.waitForTimeout(500);
      }
    }

    const sneks = await page.evaluate(() => {
      const s = window.__latestGameState;
      const target = s && s.current_target;
